  for (var i = 0; i < directSources.length; i++) { if (directSources[i]) { var n = extractNum(String(directSources[i])); if (isValidPhone(n) && !isBot(n)) { cleanNumber = n; break; } } }
  if (!cleanNumber && isGroup) {
