    if (pPn) { var pn = extractNum(String(pPn)); if (isValidPhone(pn) && !isBot(pn)) cleanNumber = pn; }
    if (!cleanNumber) { var p = extractNum(key.participant || msg.participant || ''); if (isValidPhone(p) && !isBot(p) && p.length <= 13) cleanNumber = p; }
  }
  if (!cleanNumber && isNormal) { var nn = extractNum(remoteJid); if (isValidPhone(nn)) cleanNumber = nn; }
  if (!cleanNumber) { cleanNumber = findPhoneInObj(msg, 0) || findPhoneInObj(data, 0) || findPhoneInObj(body, 0); }
