try {
  const raw = $input.first().json;
  const source = $('Preparer Filtrer Groupe').first().json;

  let extracted = {};
  let rawText = '';

  const candidates = [
    raw.output?.[0]?.content?.[0]?.text,
    raw.output?.[0]?.content?.[0],
    raw.content?.[0]?.text,
    raw.choices?.[0]?.message?.content,
    raw.text,
    raw.message?.content,
    raw.response
  ];

  for (const c of candidates) {
    if (!c) continue;
    if (typeof c === 'object' && !Array.isArray(c) && Object.keys(c).length > 0) {
      if (c.type_de_bien || c.commune || c.prix) { extracted = c; break; }
    }
    if (typeof c === 'string' && c.trim().length > 5) { rawText = c.trim(); break; }
  }

  if (rawText && Object.keys(extracted).length === 0) {
    try {
      const cleaned = rawText.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) { const parsed = JSON.parse(match[0]); if (parsed && typeof parsed === 'object') extracted = parsed; }
    } catch(e) { console.log('Parse err:', e.message); }
  }

  if (Object.keys(extracted).length === 0) {
    try {
      const fullStr = JSON.stringify(raw);
      const allMatches = fullStr.match(/\{[^{}]{20,}\}/g) || [];
      for (const m of allMatches) {
        try { const p = JSON.parse(m); if (p.type_de_bien || p.commune || p.prix) { extracted = p; break; } } catch(e) {}
      }
    } catch(e) {}
  }

  if (!extracted || Object.keys(extracted).length === 0) { console.log('REJETÉ: IA retour vide'); return []; }

  const hasTypeBien  = extracted.type_de_bien && String(extracted.type_de_bien).trim().length > 0;
  const hasCommune   = extracted.commune && String(extracted.commune).trim().length > 0;
  const hasPrix      = extracted.prix && String(extracted.prix).trim().length > 0;
  const hasTypeOffre = extracted.type_offre && String(extracted.type_offre).trim().length > 0;

  if (!hasTypeBien || !hasCommune) { console.log('REJETÉ: type_de_bien ou commune manquant'); return []; }
  if (!hasPrix && !hasTypeOffre) { console.log('REJETÉ: prix et type_offre manquants'); return []; }

  if (hasPrix) {
    const prixRaw = String(extracted.prix).toLowerCase();
    const numMatch = prixRaw.match(/(\d[\d\s.,]*)/);
    if (numMatch) {
      const numStr = numMatch[1].replace(/[\s,]/g, '').replace('.', '');
      const num = parseInt(numStr);
      const isPerM2 = prixRaw.includes('/m') || prixRaw.includes('m²') || prixRaw.includes('m2');
      const isMillion = prixRaw.includes('million') || prixRaw.includes('milion');
      let prixReel = isMillion ? num * 1000000 : num;
      if (isPerM2) { if (prixReel < 1000) return []; } else { if (prixReel < 50000 && !isMillion) return []; }
    }
  }

  const typeValides = ['appartement','studio','chambre','maison','villa','duplex','triplex','terrain','bureau','magasin','boutique','entrepot','local','immeuble','parking','garage','penthouse','parcelle','lot'];
  const typeLow = String(extracted.type_de_bien).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (!typeValides.some(t => typeLow.includes(t))) { console.log('REJETÉ: type inconnu:', extracted.type_de_bien); return []; }

  const typeMap = {'appartement':'APT','studio':'STU','chambre':'CHB','maison':'MAS','villa':'VIL','duplex':'DPX','triplex':'TRX','terrain':'TER','parcelle':'PAR','lot':'LOT','bureau':'BUR','magasin':'MAG','boutique':'BTQ','local':'LOC','entrepot':'ENT','immeuble':'IMM','garage':'GAR','parking':'PRK','penthouse':'PNT'};
  const typeCode = Object.entries(typeMap).find(([k]) => typeLow.includes(k))?.[1] || 'BIE';
  const commCode = String(extracted.commune).substring(0, 3).toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const offreCode = String(extracted.type_offre || '').toLowerCase().includes('vente') ? 'V' : 'L';
  const rand = Math.random().toString(36).substring(2, 10).toUpperCase();
  const ref_bien = typeCode + '-' + commCode + '-' + offreCode + '-' + rand;

  const hashInput = [typeLow, String(extracted.prix||'').toLowerCase().replace(/\s/g,''), String(extracted.commune||'').toLowerCase(), String(extracted.quartier||'').toLowerCase(), String(extracted.chambre||''), String(extracted.surface||''), String(extracted.caracteristiques||'').substring(0,150).toLowerCase().replace(/\s/g,'')].join('|');
  let hash = 5381;
  for (let i = 0; i < hashInput.length; i++) { hash = ((hash << 5) + hash + hashInput.charCodeAt(i)) & 0xFFFFFFFF; }
  const content_hash = (hash >>> 0).toString(16).padStart(8, '0');

  const dateExp = new Date(); dateExp.setDate(dateExp.getDate() + 30);

  return [{ json: {
    ref_bien, content_hash,
    type_de_bien: String(extracted.type_de_bien || ''),
    type_offre: String(extracted.type_offre || ''),
    zone_geographique: String(extracted.zone_geographique || ''),
