    telephone_bien: String(extracted.telephone || source.telephone || ''),
    telephone_expediteur: String(source.wasenderPhone || source.telephone || ''),
    expediteur: String(source.expediteur || ''),
    publie_par: String(extracted.publie_par || source.expediteur || ''),
