function textSimilarity(str1, str2) {
  const s1 = (str1||'').toLowerCase().replace(/[^a-z0-9]/g,'');
  const s2 = (str2||'').toLowerCase().replace(/[^a-z0-9]/g,'');
  if (s1===s2) return 1; if (s1.length<3||s2.length<3) return 0;
  let bigrams1=new Map();
  for(let i=0;i<s1.length-2;i++){const big=s1.substring(i,i+3);bigrams1.set(big,(bigrams1.get(big)||0)+1);}
  let intersectionSize=0;
  for(let i=0;i<s2.length-2;i++){const big=s2.substring(i,i+3);const count=bigrams1.get(big);if(count>0){bigrams1.set(big,count-1);intersectionSize++;}}
  return (2.0*intersectionSize)/(s1.length+s2.length-4);
}

